  `}function zP(t){var s;const e=yn(t),a=t.demandSnapshot.skuLines.reduce((r,o)=>r+o.qty,0);if(p.detailTab==="overview"){const r=(()=>{if(t.ownerPartyType==="FACTORY")return t.ownerPartyId===t.mainFactoryId?{text:"主工厂",detail:t.mainFactorySnapshot.name,adjusted:!1}:{text:"工厂（已调整）",detail:t.ownerPartyId,adjusted:!0};const o=Qu.find(i=>i.id===t.ownerPartyId);return{text:(o==null?void 0:o.name)??"法人实体",detail:t.ownerReason??"",adjusted:!0}})();return`
